// Normalize form submit, gen booking_code, build wa.me link
let body = $input.item.json.body || $input.item.json;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
body = body || {};

function genCode() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let r = 'EX-';
  for (let i = 0; i < 8; i++) r += chars[Math.floor(Math.random()*chars.length)];
  return r;
}

const booking_code = genCode();
const telYaz = '529982XXXXXXX';

let servicios = body.servicios;
if (typeof servicios === 'string') servicios = [{ slug: servicios }];
if (!Array.isArray(servicios)) servicios = [];

const servicioSlug = servicios[0]?.slug || 'masaje';
const pref = (body.preferencia_sexo || 'I').toUpperCase();
const prefTexto = pref === 'H' ? 'Hombre' : pref === 'M' ? 'Mujer' : 'Indistinto';
const zona = body.zona_colonia || 'Cancun';
const waText = ('Hola, quiero reservar un masaje ' + servicioSlug + ' en zona ' + zona + '. Preferencia: ' + prefTexto + '. Folio ' + booking_code + '.')
  .normalize('NFD').replace(/[\u0300-\u036f]/g,'');
const wa_link = 'https://wa.me/' + telYaz + '?text=' + encodeURIComponent(waText);

const payload = {
  booking_code,
  lead_ref: body.lead_ref || null,
  ghl_contact_id: body.ghl_contact_id || null,
  cliente_nombre: body.cliente_nombre || null,
  cliente_telefono: body.cliente_telefono || null,
  cliente_email: body.cliente_email || null,
  servicios: servicios,
  preferencia_sexo: pref,
  zona_municipio: 'Cancun',
  zona_colonia: body.zona_colonia || null,
  direccion_libre: body.direccion_libre || null,
  direccion_maps_url: body.direccion_maps_url || null,
  notas_cliente: body.notas_cliente || null,
  modo_asignacion: 'whatsapp_group',
  estado: 'reservo'
};
return { json: { payload, booking_code, wa_link } };

return [{ json: {
  success: true,
  booking_code: $('Postgres').item.json.booking_code,
  id: $('Postgres').item.json.id,
  wa_link: $('Normalize').item.json.wa_link
} }];
